mapper.select:
SELECT *
FROM account_move_line


        AND id = #{query.id}


        AND move_id = #{query.moveId}


        AND account_id = #{query.accountId}


        AND product_id = #{query.productId}


        AND reconciled = #{query.reconciled}


        AND payment_ref = #{query.paymentRef}


        AND (
            name ILIKE CONCAT('%', #{query.keyword}, '%')
            OR payment_ref ILIKE CONCAT('%', #{query.keyword}, '%')
        )


ORDER BY id DESC
